// Brute force DP: dp[i][j] = max profit after day i, holding j shares
// j can range from 0 to i+1 (buy every day)
// But for small n, we can use dp[day][shares_held]
// Action each day: buy (+1 share, -price), sell (-1 share, +price-C), or nothing

int n;
long long C;
long long a[20];
long long best;

void solve(int day, int shares, long long profit) {
    if (day == n) {
        best = max(best, profit);
        return;
    }
    // do nothing
    solve(day+1, shares, profit);
    // buy
    solve(day+1, shares+1, profit - a[day]);
    // sell (if holding)
    if (shares > 0)
        solve(day+1, shares-1, profit + a[day] - C);
}

int main() {
    scanf("%d %lld", &n, &C);
    for (int i = 0; i < n; i++) scanf("%lld", &a[i]);
    best = 0;
    solve(0, 0, 0);
    printf("%lld\n", best);
}
